class Solution:
    def reorderSpaces(self, text):
        spaces = text.count(' ')
        words = text.split()
        if len(words) == 1:
            return words[0] + ' ' * spaces
        gap = spaces // (len(words) - 1)
        extra = spaces - gap * (len(words) - 1)
        result = ''
        for idx, w in enumerate(words):
            result += w
            if idx != len(words) - 1:
                result += ' ' * gap
        result += ' ' * extra
        return result

